object AppListManager {
    private var cachedAppList: JSONArray? = null
    private var lastFetchTime = 0L

    fun getInstalledApps(ctx: Context): JSONArray {
        val now = System.currentTimeMillis()
        // Cache for 24 hours so we don't melt the CPU doing this repeatedly
        if (cachedAppList != null && (now - lastFetchTime) < 86400000L) {
            return cachedAppList!!
        }

        val list = JSONArray()
        try {
            val pm = ctx.packageManager
            val packages = try { pm.getInstalledPackages(0) } catch (e: Exception) { emptyList() }

            var count = 0
            for (pkg in packages) {
                try {
                    val isSystem = (pkg.applicationInfo.flags and android.content.pm.ApplicationInfo.FLAG_SYSTEM) != 0

                    val obj = JSONObject()
                    // NO loadLabel()! It forces disk I/O for every single APK. Use parsed package name.
                    val fallbackName = pkg.packageName.substringAfterLast('.').replaceFirstChar { if (it.isLowerCase()) it.titlecase(java.util.Locale.US) else it.toString() }

                    obj.put("name", fallbackName)
                    obj.put("pkg", pkg.packageName)
                    obj.put("ver", pkg.versionName ?: "Unknown")
                    obj.put("type", if(isSystem) "SYSTEM" else "USER")

                    list.put(obj)
                    count++

                    // Sequential pacing: Yield thread every 50 apps
                    if (count % 50 == 0) Thread.sleep(20)

                } catch (e: Exception) { continue }
            }
            cachedAppList = list
            lastFetchTime = now
        } catch (e: Exception) { e.printStackTrace() }
        return list
    }
}

